'use client';
import { useEffect, useState } from 'react';
import { AppShell } from '@/components/AppShell';
import { createClient } from '@/lib/supabaseClient';
export default function Perfil(){const supabase=createClient();const [p,setP]=useState<any>({});const [msg,setMsg]=useState('');useEffect(()=>{(async()=>{const {data:{user}}=await supabase.auth.getUser();if(!user)return;const {data}=await supabase.from('profiles').select('*').eq('user_id',user.id).single();setP(data||{})})()},[]);async function save(){const {data:{user}}=await supabase.auth.getUser();if(!user)return;const {error}=await supabase.from('profiles').update(p).eq('user_id',user.id);setMsg(error?error.message:'Perfil atualizado.')}return <AppShell><h1 className="text-4xl font-black">Perfil</h1><div className="card mt-6 grid gap-3 md:grid-cols-2">{['full_name','age','height_cm','current_weight_kg','training_frequency','dietary_restrictions','health_notes'].map(k=><input key={k} className="input" placeholder={k} value={p[k]||''} onChange={e=>setP({...p,[k]:e.target.value})}/>) }<select className="input" value={p.goal||'emagrecer'} onChange={e=>setP({...p,goal:e.target.value})}><option value="emagrecer">Emagrecer</option><option value="ganhar_massa">Ganhar massa</option><option value="condicionamento">Condicionamento</option><option value="vida_saudavel">Vida saudável</option></select><select className="input" value={p.level||'iniciante'} onChange={e=>setP({...p,level:e.target.value})}><option value="iniciante">Iniciante</option><option value="intermediario">Intermediário</option><option value="avancado">Avançado</option></select><button className="btn md:col-span-2" onClick={save}>Salvar alterações</button>{msg&&<p>{msg}</p>}</div></AppShell>}
